pub(all) suberror PortError {
  Invalid
}

pub fn parse_port(s : String) -> Int raise PortError {
  if s == "" {
    raise PortError::Invalid
  }
  let mut n = 0
  for c in s {
    if c is ('0'..='9') {
      n = n * 10 + (c.to_int() - 48)
    } else {
      raise PortError::Invalid
    }
  }
  if n > 0 && n <= 65535 {
    n
  } else {
    raise PortError::Invalid
  }
}

