test "valid port" {
  assert_eq(@ports.parse_port("8080"), 8080)
}

test "invalid port" {
  try @ports.parse_port("80x0") catch {
    @ports.PortError::Invalid => ()
  } noraise {
    _ => fail("expected error")
  }
}

